scwin.sbm_retrieve_submitdone = async function (e) {
  let rowCnt = ds_results.getRowCount();
  if (rowCnt == 0) {
    await $c.gus.cfAlertMsg($p, "조회된 데이터가 없습니다.");
    return false;
  }
  tbx_totalCount.setValue(rowCnt);
  if (lc_lobranCd.getValue() == "Y") {
    $c.gus.cfEnableObjects($p, [btn_delRow]);
    $c.gus.cfDisableObjects($p, [btn_saveAndAutoEDI, btn_saveAndManualEDI]);
    ds_resultsVehcl.removeAll();
  } else {
    $c.gus.cfDisableObjects($p, [btn_delRow]);
    $c.gus.cfEnableObjects($p, [btn_saveAndAutoEDI, btn_saveAndManualEDI]);
    let tempTime = "";
    for (let i = 0; i < rowCnt; i++) {
      if (ds_results.getCellData(i, "closeTime") != "") {
        tempTime = ds_results.getCellData(i, "closeTime");
        tempTime = tempTime.substr(0, 2) + "/" + tempTime.substr(2, 2) + " " + tempTime.substr(4, 2) + ":" + tempTime.substr(6, 2);
        ds_results.setCellData(i, "closeTime", tempTime);
      }
      if (ds_results.getCellData(i, "chassShortNo") != "") {
        scwin.f_openCommPopUpGrid(2, i, "T");
      }
    }
  }
  if (lc_lobranCd.getValue() == "N") {
    for (let j = 0; j < ds_results.getRowCount(); j++) {
      if (ds_results.getCellData(j, "openYn") == 1 && ds_results.getCellData(j, "chkMobile") == "Y") {
        let lobranCdVal = scwin.v_wrkLobranCd;
        let stDt = scwin.v_dptIntendDd;
        let endDt = scwin.v_dptIntendDd2;
        let odrNo = scwin.v_cntrOdrNo;
        let pURL = "/ui/tn/op/rscmgnt/tn_305_01_09b.xml";
        let paramObj = {
          paramTitle: "관심물량등록차량",
          lobranCd: lobranCdVal,
          wrkDistrictCd1: "",
          clntNo: "",
          stDt: stDt,
          endDt: endDt,
          odrKndCd: "",
          noClsCd: "",
          odrNo: odrNo,
          railroadAdptDstCd: "",
          cargoClsCd: "C"
        };
        let rtnList = await $c.win.openPopup($p, pURL, {
          width: 500,
          height: 240,
          modal: true,
          data: paramObj
        });
        if (rtnList != null) {
          for (let i = 0; i < ds_results.getRowCount(); i++) {
            if (ds_results.getCellData(i, "odrNo") == rtnList[10] && ds_results.getCellData(i, "openYn") == 1) {
              if (rtnList[0].trim() != "N/A") {
                ds_results.setCellData(i, "vehclShortNo", rtnList[0]);
                ds_results.setCellData(i, "vehclNo", rtnList[2]);
                ds_results.setCellData(i, "eqCd", rtnList[8]);
                ds_results.setCellData(i, "chk", 1);
              }
            }
          }
        }
        break;
      }
    }
  }
};
