scwin.f_Save = async function (retrieveYn) {
  if (ds_results.getUpdatedIndex().length == 0) {
    await $c.win.alert($p, "변경된 사항이 없습니다.");
    return;
  }
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "vehclClntNo") == ds_results.getCellData(i, "bilgClntNo")) {
      await $c.win.alert($p, "오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
      return false;
    }
  }
  if (lc_lobranCd.getValue() == "N") {
    for (let i = 0; i < ds_results.getRowCount(); i++) {
      if (ds_results.getRowStatus(i) == "U") {
        if (ds_results.getCellData(i, "cntrWrkShapeCd") != "") {
          if (ds_results.getCellData(i, "wrkStpCd") == "0002") {
            if (i + 1 < ds_results.getRowCount() && ds_results.getCellData(i + 1, "wrkStpCd") == "0003" && ds_results.getCellData(i + 1, "vehclNo") != "") {
              if (ds_results.getCellData(i, "odrNo") == ds_results.getCellData(i + 1, "odrNo") && ds_results.getCellData(i, "cntrSeq") == ds_results.getCellData(i + 1, "cntrSeq")) {
                await $c.win.alert($p, "DOOR운송 배차시, BOBTAIL, ON-GROUND를 선택하고 배차할 때는 회수단계는 차량이 없어야 합니다.");
                ds_results.setCellData(i + 1, "vehclNo", "");
                ds_results.setCellData(i + 1, "vehclShortNo", "");
                return false;
              }
            }
          } else if (ds_results.getCellData(i, "wrkStpCd") == "0003") {
            if (i - 1 >= 0 && ds_results.getCellData(i - 1, "wrkStpCd") == "0002" && ds_results.getCellData(i - 1, "vehclNo") != "") {
              if (ds_results.getCellData(i, "odrNo") == ds_results.getCellData(i - 1, "odrNo") && ds_results.getCellData(i, "cntrSeq") == ds_results.getCellData(i - 1, "cntrSeq")) {
                await $c.win.alert($p, "DOOR회수 배차시, BOBTAIL, ON-GROUND를 선택하고 운송단계보다 먼저 배차할 수 없습니다.");
                ds_results.setCellData(i - 1, "vehclNo", "");
                ds_results.setCellData(i - 1, "vehclShortNo", "");
                ds_results.setCellData(i, "vehclNo", "");
                ds_results.setCellData(i, "vehclShortNo", "");
                return false;
              }
            }
          } else if (ds_results.getCellData(i, "wrkStpCd") == "0047") {
            await $c.win.alert($p, "육송 단계는 BOBTAIL, ON-GROUND로 배차할 수 없습니다");
            return false;
          }
        }
        if (ds_results.getCellData(i, "dcScAmt") > 0) {
          if (ds_results.getCellData(i, "dcScNm") == "") {
            await $c.win.alert($p, "할인할증금액은 팝업을 띄워서 할인할증항목을 선택하고, 금액을 입력한 후, 저장하셔야 합니다");
            return false;
          }
        }
      }
    }
  }
  if (lc_lobranCd.getValue() == "Y") {
    for (let i = 0; i < ds_results.getRowCount(); i++) {
      if (ds_results.getRowStatus(i) == "U") {
        if (ds_results.getCellData(i, "cooperatorYn") == 1) {
          if (ds_results.getCellData(i, "vehclNo") != "") {
            await $c.win.alert($p, "컨테이너 " + ds_results.getCellData(i, "cntrNo") + " 는 협력업체에서 이미 배차한 물량은 취소할 수 없습니다. \n협력업체에서 먼저 배차를 취소한 후 취소할 수 있습니다.");
            return false;
          }
        }
      }
    }
  }
  scwin.afterSaveRetrieveYN = retrieveYn;
  await $c.sbm.execute($p, sbm_save);
};
