scwin.f_SaveAndAutoEDI = async function (flag) {
  if (lc_lobranCd.getValue() == "Y") {
    await $c.win.alert($p, "배차후에는 이용할 수 없습니다.");
    return false;
  }
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getCellData(i, "vehclClntNo") == ds_results.getCellData(i, "bilgClntNo")) {
      await $c.win.alert($p, "오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
      return false;
    }
  }
  let arrParam = [];
  for (let i = 0; i < ds_results.getRowCount(); i++) {
    if (ds_results.getRowStatus(i) == "U" || ds_results.getCellData(i, "chk") == 1) {
      arrParam.push(i);
    }
  }
  await scwin.f_Save("NO");
  for (let i = 0; i < arrParam.length; i++) {
    let idx = arrParam[i];
    if (ds_results.getCellData(idx, "vehclNo") == "") {
      await $c.win.alert($p, "컨테이너 " + ds_results.getCellData(idx, "cntrNo") + " 는 차량번호가 없어서 전송할 수 없습니다.");
      continue;
    } else {
      if (ds_results.getCellData(idx, "crryinEdiFlag") == "N" && ds_results.getCellData(idx, "crryoutEdiFlag") == "N") {
        await $c.gus.cfAlertMsg($p, "컨테이너 " + ds_results.getCellData(idx, "cntrNo") + ", " + ds_results.getCellData(idx, "dptWrkPlNm") + ", " + ds_results.getCellData(idx, "arvWrkPlNm") + " 는 EDI등록 대상이 아닙니다");
        continue;
      }
      if (ds_results.getCellData(idx, "crryoutEdiType") != "CO" && ds_results.getCellData(idx, "crryoutEdiType") != "CD" && ds_results.getCellData(idx, "crryinEdiType") != "CO" && ds_results.getCellData(idx, "crryinEdiType") != "CD") {
        await $c.gus.cfAlertMsg($p, "컨테이너 " + ds_results.getCellData(idx, "cntrNo") + ", " + ds_results.getCellData(idx, "dptWrkPlNm") + ", " + ds_results.getCellData(idx, "arvWrkPlNm") + " 는 EDI등록 대상이 아닙니다");
        continue;
      }
      if (flag == "AUTO") {
        await scwin.f_crryInOutEDI(false, true, true, idx, true);
      } else if (flag == "MANUAL") {
        await scwin.f_crryInOutEDI(false, false, false, idx, true);
      }
    }
  }
  scwin.f_Retrieve();
};
